// ---- Input validation ----
// Only accept known string fields; truncate to safe lengths to prevent
// oversized payloads and content-injection attacks from untrusted callers.
const MAX_SHORT = 200;
const MAX_LONG  = 2000;

function safeStr(val, max) {
  if (typeof val !== 'string') return undefined;
  return val.trim().slice(0, max) || undefined;
}

const raw = $json.body || $json;

// Allowlist — only extract expected fields, ignore everything else
const data = {
  name:        safeStr(raw.name,        MAX_SHORT),
  email:       safeStr(raw.email,       MAX_SHORT),
  company:     safeStr(raw.company,     MAX_SHORT),
  title:       safeStr(raw.title,       MAX_SHORT),
  phone:       safeStr(raw.phone,       MAX_SHORT),
  notes:       safeStr(raw.notes,       MAX_LONG),
  message:     safeStr(raw.message,     MAX_LONG),
  source:      safeStr(raw.source,      MAX_SHORT),
  website:     safeStr(raw.website || raw.website_url, MAX_SHORT),
};

// Validate email format before forwarding
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (data.email && !EMAIL_RE.test(data.email)) {
  data.email = undefined;
}

// Build content string only from validated fields
const parts = [];
if (data.name)    parts.push('Name: '    + data.name);
if (data.email)   parts.push('Email: '   + data.email);
if (data.company) parts.push('Company: ' + data.company);
if (data.title)   parts.push('Title: '   + data.title);
if (data.phone)   parts.push('Phone: '   + data.phone);
if (data.notes)   parts.push('Notes: '   + data.notes);
if (data.message) parts.push('Message: ' + data.message);

if (parts.length === 0) {
  throw new Error('Webhook payload contained no recognised fields after validation. Dropping item.');
}

const content = parts.join('\n');

return [{
  json: {
    content,
    speaker: data.source || 'webhook',
    enhanced: true,
    tags: ['webhook', 'real-time', data.source || 'unknown'].filter(Boolean),
    email:       data.email   || undefined,
    website_url: data.website || undefined,
  }
}];

const result = $input.first().json;
return [{
  json: {
    success: result.success || false,
    message: result.success ? 'Memorized successfully' : 'Failed to memorize',
    data: result.data || null
  }
}];
